L1: package fan.summer.ui.content;
L2: 
L3: import fan.summer.api.MdiIconUtil;
L4: import fan.summer.api.SwissKitJPlugin;
L5: import javafx.animation.Interpolator;
L6: import javafx.animation.KeyFrame;
L7: import javafx.animation.KeyValue;
L8: import javafx.animation.Timeline;
L9: import javafx.geometry.Insets;
L10: import javafx.geometry.Pos;
L11: import javafx.scene.control.Button;
L12: import javafx.scene.control.Label;
L13: import javafx.scene.control.Separator;
L14: import javafx.scene.effect.DropShadow;
L15: import javafx.scene.layout.*;
L16: import javafx.scene.paint.Color;
L17: import javafx.scene.text.Text;
L18: import javafx.util.Duration;
L19: 
L20: import java.util.function.Consumer;
L21: 
L22: /**
L23:  * Tool detail panel, slides in from right.
L24:  * show(plugin) fills data and expands; hide() collapses.
L25:  */
L26: public class DetailPanel extends VBox {
L27: 
L28:     private static final double PANEL_WIDTH = 260;
L29: 
L30:     private Text        iconText    = new Text();
L31:     private final StackPane iconWrap   = new StackPane(iconText);
L32:     private final Label   nameLabel   = new Label();
L33:     private final Label   metaLabel   = new Label();
L34:     private final Label   descLabel   = new Label();
L35:     private final Label   versionVal  = new Label();
L36:     private final Label   typeVal     = new Label();
L37:     private final Label   categoryVal = new Label();
L38:     private final Button  launchBtn  = new Button("Launch Tool");
L39:     private final Button  closeBtn   = new Button("✕");
L40: 
L41:     private Consumer<SwissKitJPlugin> onLaunch;
L42:     private SwissKitJPlugin currentPlugin;
L43:     private boolean    panelOpen = false;
L44: 
L45:     public DetailPanel() {
L46:         getStyleClass().add("detail-panel");
L47:         setPrefWidth(0);
L48:         setMinWidth(0);
L49:         setMaxWidth(PANEL_WIDTH);
L50: 
L51:         buildUI();
L52:         setVisible(false);
L53:     }
L54: 
L55:     public void setOnLaunch(Consumer<SwissKitJPlugin> handler) {
L56:         this.onLaunch = handler;
L57:     }
L58: 
L59:     public void show(SwissKitJPlugin plugin) {
L60:         this.currentPlugin = plugin;
L61:         fillData(plugin);
L62:         if (!panelOpen) slideIn();
L63:     }
L64: 
L65:     public void hide() {
L66:         if (panelOpen) slideOut();
L67:     }
L68: 
L69:     public boolean isPanelOpen() { return panelOpen; }
L70: 
L71:     private void buildUI() {
L72:         iconWrap.setPrefSize(56, 56);
L73:         iconWrap.setMinSize(56, 56);
L74:         iconWrap.getStyleClass().add("tool-icon-wrap");
L75: 
L76:         nameLabel.getStyleClass().add("tool-name");
L77:         nameLabel.setStyle("-fx-font-size: 16px;");
L78: 
L79:         metaLabel.getStyleClass().add("status-text");
L80:         metaLabel.setStyle("-fx-font-size: 11px;");
L81: 
L82:         descLabel.getStyleClass().add("tool-desc");
L83:         descLabel.setWrapText(true);
L84:         descLabel.setStyle("-fx-font-size: 12.5px;");
L85: 
L86:         launchBtn.getStyleClass().add("detail-launch-btn");
L87:         launchBtn.setMaxWidth(Double.MAX_VALUE);
L88:         launchBtn.setOnAction(e -> {
L89:             if (onLaunch != null && currentPlugin != null)
L90:                 onLaunch.accept(currentPlugin);
L91:         });
L92: 
L93:         closeBtn.setStyle(
L94:             "-fx-background-color: transparent; -fx-border-width: 0;" +
L95:             "-fx-text-fill: rgba(255,255,255,0.35); -fx-cursor: hand; -fx-font-size: 14px;"
L96:         );
L97:         closeBtn.setOnAction(e -> hide());
L98:         closeBtn.setOnMouseEntered(e ->
L99:             closeBtn.setStyle(closeBtn.getStyle() + "-fx-text-fill: rgba(255,255,255,0.85);"));
L100:         closeBtn.setOnMouseExited(e ->
L101:             closeBtn.setStyle(closeBtn.getStyle().replace("-fx-text-fill: rgba(255,255,255,0.85);", "")));
L102: 
L103:         HBox topRow = new HBox(closeBtn);
L104:         topRow.setAlignment(Pos.CENTER_RIGHT);
L105: 
L106:         Separator sep = new Separator();
L107:         sep.setStyle("-fx-border-color: rgba(255,255,255,0.10); -fx-padding: 8 0 8 0;");
L108: 
L109:         VBox propsBox = new VBox(6,
L110:             propRow("Version",   versionVal),
L111:             propRow("Type",      typeVal),
L112:             propRow("Category",  categoryVal)
L113:         );
L114: 
L115:         setSpacing(10);
L116:         setPadding(new Insets(16));
L117:         getChildren().addAll(
L118:             topRow, iconWrap, nameLabel, metaLabel, descLabel,
L119:             launchBtn, sep, propsBox
L120:         );
L121:     }
L122: 
L123:     private HBox propRow(String key, Label valLabel) {
L124:         Label keyLabel = new Label(key);
L125:         keyLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.30); -fx-font-size: 12px;");
L126:         valLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.55); -fx-font-size: 12px; " +
L127:                           "-fx-font-family: 'SF Mono','Consolas',monospace;");
L128:         Region spacer = new Region();
L129:         HBox.setHgrow(spacer, Priority.ALWAYS);
L130:         return new HBox(keyLabel, spacer, valLabel);
L131:     }
L132: 
L133:     private void fillData(SwissKitJPlugin p) {
L134:         // Rebuild icon the same way as ToolCard
L135:         Color color = resolveColor(p.getIconStyle());
L136:         String fillStyle = String.format("-fx-fill: rgba(%d,%d,%d,1.0);",
L137:                 (int)(color.getRed()*255),
L138:                 (int)(color.getGreen()*255),
L139:                 (int)(color.getBlue()*255));
L140: 
L141:         Text newIcon = MdiIconUtil.createIcon(p.getMdiIcon(), 50);
L142:         newIcon.setStyle(fillStyle);
L143: 
L144:         DropShadow glow = new DropShadow();
L145:         glow.setColor(color.deriveColor(0, 1, 1, 0.75));
L146:         glow.setRadius(14);
L147:         glow.setSpread(0.18);
L148:         newIcon.setEffect(glow);
L149: 
L150:         iconWrap.getChildren().setAll(newIcon);
L151:         this.iconText = newIcon;
L152: 
L153:         nameLabel.setText(p.getName());
L154:         metaLabel.setText("v" + p.getVersion() + " · " + p.getType());
L155:         descLabel.setText(p.getDescription());
L156: 
L157:         versionVal.setText(p.getVersion());
L158:         typeVal.setText(p.getType());
L159:         categoryVal.setText(categoryName(p.getCategory()));
L160:     }
L161: 
L162:     private static Color resolveColor(String iconStyle) {
L163:         return switch (iconStyle) {
L164:             case "ic-blue"   -> Color.rgb(99, 130, 255);
L165:             case "ic-purple" -> Color.rgb(160, 110, 255);
L166:             case "ic-teal"   -> Color.rgb(40, 210, 140);
L167:             case "ic-amber"  -> Color.rgb(255, 185, 50);
L168:             case "ic-red"    -> Color.rgb(255, 100, 100);
L169:             case "ic-pink"   -> Color.rgb(245, 100, 160);
L170:             default          -> Color.rgb(200, 200, 210);
L171:         };
L172:     }
L173: 
L174:     private String categoryName(String cat) {
L175:         return switch (cat) {
L176:             case "dev"   -> "Developer Tools";
L177:             case "text"  -> "Text Processing";
L178:             case "image" -> "Image Processing";
L179:             case "net"   -> "Network Tools";
L180:             default      -> cat;
L181:         };
L182:     }
L183: 
L184:     private void slideIn() {
L185:         panelOpen = true;
L186:         setVisible(true);
L187: 
L188:         Timeline tl = new Timeline(
L189:             new KeyFrame(Duration.ZERO,
L190:                 new KeyValue(prefWidthProperty(), 0),
L191:                 new KeyValue(opacityProperty(), 0)
L192:             ),
L193:             new KeyFrame(Duration.millis(300),
L194:                 new KeyValue(prefWidthProperty(), PANEL_WIDTH,
L195:                     Interpolator.SPLINE(0.4, 0, 0.2, 1)),
L196:                 new KeyValue(opacityProperty(), 1,
L197:                     Interpolator.EASE_OUT)
L198:             )
L199:         );
L200:         tl.play();
L201:     }
L202: 
L203:     private void slideOut() {
L204:         panelOpen = false;
L205:         Timeline tl = new Timeline(
L206:             new KeyFrame(Duration.ZERO,
L207:                 new KeyValue(prefWidthProperty(), PANEL_WIDTH),
L208:                 new KeyValue(opacityProperty(), 1)
L209:             ),
L210:             new KeyFrame(Duration.millis(250),
L211:                 new KeyValue(prefWidthProperty(), 0,
L212:                     Interpolator.SPLINE(0.4, 0, 0.2, 1)),
L213:                 new KeyValue(opacityProperty(), 0,
L214:                     Interpolator.EASE_IN)
L215:             )
L216:         );
L217:         tl.setOnFinished(e -> setVisible(false));
L218:         tl.play();
L219:     }
L220: }
