L1: package fan.summer.ui.content;
L2: 
L3: import fan.summer.api.SwissKitJPlugin;
L4: import javafx.animation.FadeTransition;
L5: import javafx.animation.ParallelTransition;
L6: import javafx.animation.PauseTransition;
L7: import javafx.animation.TranslateTransition;
L8: import javafx.collections.ListChangeListener;
L9: import javafx.collections.ObservableList;
L10: import javafx.geometry.Insets;
L11: import javafx.geometry.Pos;
L12: import javafx.scene.Node;
L13: import javafx.scene.control.Label;
L14: import javafx.scene.control.ScrollPane;
L15: import javafx.scene.control.TextField;
L16: import javafx.scene.layout.*;
L17: import javafx.util.Duration;
L18: 
L19: import java.util.List;
L20: import java.util.function.Consumer;
L21: 
L22: /**
L23:  * Main content area.
L24:  * Contains: Search bar / Tool grid / Detail panel / Page transition animations.
L25:  * Bind plugin data via setPlugins(ObservableList), auto-respond to add/remove.
L26:  */
L27: public class ContentArea extends BorderPane {
L28: 
L29:     // ── Sub-components ────────────────────────────────────────────
L30:     private final TextField   searchField  = new TextField();
L31:     private final FlowPane    toolGrid     = new FlowPane();
L32:     private final DetailPanel detailPanel  = new DetailPanel();
L33:     private final StackPane   pageStack    = new StackPane();
L34:     private final ScrollPane  scrollPane;
L35:     private final ScrollPane  pageScrollPane;
L36:     private final HBox        backBar      = buildBackBar();
L37: 
L38:     // ── State ──────────────────────────────────────────────
L39:     private ObservableList<SwissKitJPlugin> plugins;
L40:     private String   currentCategory = "all";
L41:     private String   currentQuery    = "";
L42:     private Consumer<SwissKitJPlugin> onLaunch;
L43:     private Runnable onBack;
L44: 
L45:     public ContentArea() {
L46:         scrollPane     = buildScrollPane();
L47:         pageScrollPane = buildPageScrollPane();
L48:         buildLayout();
L49:         detailPanel.setOnLaunch(p -> { if (onLaunch != null) onLaunch.accept(p); });
L50:     }
L51: 
L52:     // ── Public API ──────────────────────────────────────────
L53: 
L54:     public void setOnLaunch(Consumer<SwissKitJPlugin> handler) { this.onLaunch = handler; }
L55:     public void setOnBack(Runnable handler) { this.onBack = handler; }
L56: 
L57:     /** Bind plugin list, auto-refresh on add/remove */
L58:     public void setPlugins(ObservableList<SwissKitJPlugin> list) {
L59:         this.plugins = list;
L60:         list.addListener((ListChangeListener<SwissKitJPlugin>) c -> refresh());
L61:         refresh();
L62:     }
L63: 
L64:     /** Switch category display */
L65:     public void showCategory(String categoryId) {
L66:         currentCategory = categoryId;
L67:         searchField.clear();
L68:         currentQuery = "";
L69:         setTopMode(false, null);
L70:         crossFadeTo(scrollPane);
L71:         refresh();
L72:         animateGridIn();
L73:     }
L74: 
L75:     /** Switch to custom page (e.g. settings, plugin market) */
L76:     public void showPage(Node page, String title) {
L77:         pageScrollPane.setContent(page);
L78:         setTopMode(true, title);
L79:         crossFadeTo(pageScrollPane);
L80:         detailPanel.hide();
L81:     }
L82: 
L83:     /** Back to tool grid home */
L84:     public void showToolGrid() {
L85:         setTopMode(false, null);
L86:         crossFadeTo(scrollPane);
L87:     }
L88: 
L89:     private void setTopMode(boolean pageMode, String title) {
L90:         if (pageMode) {
L91:             Label titleLabel = (Label) backBar.lookup(".back-title");
L92:             if (titleLabel != null) titleLabel.setText(title != null ? title : "");
L93:             backBar.setVisible(true);
L94:             backBar.setManaged(true);
L95:             searchField.getParent().setVisible(false);
L96:             searchField.getParent().setManaged(false);
L97:         } else {
L98:             backBar.setVisible(false);
L99:             backBar.setManaged(false);
L100:             searchField.getParent().setVisible(true);
L101:             searchField.getParent().setManaged(true);
L102:         }
L103:     }
L104: 
L105:     // ── Layout build ──────────────────────────────────────────
L106: 
L107:     private void buildLayout() {
L108:         // Search bar
L109:         HBox searchBar = buildSearchBar();
L110: 
L111:         // Top area: back bar (hidden by default) + search bar
L112:         backBar.setVisible(false);
L113:         backBar.setManaged(false);
L114:         VBox top = new VBox(backBar, searchBar);
L115:         top.setPadding(new Insets(12, 16, 0, 16));
L116:         setTop(top);
L117: 
L118:         // Center: StackPane (switchable content) + Detail panel
L119:         pageStack.getChildren().add(scrollPane);
L120:         pageStack.setAlignment(Pos.TOP_LEFT);
L121: 
L122:         HBox center = new HBox(pageStack, detailPanel);
L123:         HBox.setHgrow(pageStack, Priority.ALWAYS);
L124:         setCenter(center);
L125:     }
L126: 
L127:     private HBox buildBackBar() {
L128:         Label backBtn = new Label("← 返回");
L129:         backBtn.setStyle(
L130:             "-fx-text-fill: rgba(255,255,255,0.70); -fx-font-size: 13px;" +
L131:             "-fx-cursor: hand; -fx-padding: 4 10 4 0;"
L132:         );
L133:         backBtn.setOnMouseEntered(e ->
L134:             backBtn.setStyle("-fx-text-fill: rgba(255,255,255,1); -fx-font-size: 13px;" +
L135:                              "-fx-cursor: hand; -fx-padding: 4 10 4 0;")
L136:         );
L137:         backBtn.setOnMouseExited(e ->
L138:             backBtn.setStyle("-fx-text-fill: rgba(255,255,255,0.70); -fx-font-size: 13px;" +
L139:                              "-fx-cursor: hand; -fx-padding: 4 10 4 0;")
L140:         );
L141:         backBtn.setOnMouseClicked(e -> {
L142:             showToolGrid();
L143:             if (onBack != null) onBack.run();
L144:         });
L145: 
L146:         Label sep = new Label("/");
L147:         sep.setStyle("-fx-text-fill: rgba(255,255,255,0.25); -fx-font-size: 13px; -fx-padding: 4 6 4 0;");
L148: 
L149:         Label titleLabel = new Label();
L150:         titleLabel.getStyleClass().add("back-title");
L151:         titleLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.90); -fx-font-size: 13px; -fx-font-weight: bold;");
L152: 
L153:         HBox bar = new HBox(6, backBtn, sep, titleLabel);
L154:         bar.setAlignment(Pos.CENTER_LEFT);
L155:         bar.setPrefHeight(38);
L156:         return bar;
L157:     }
L158: 
L159:     private HBox buildSearchBar() {
L160:         Label searchIcon = new Label("🔍");
L161:         searchIcon.setStyle("-fx-font-size: 13px; -fx-text-fill: rgba(255,255,255,0.28);");
L162: 
L163:         searchField.getStyleClass().add("search-field");
L164:         searchField.setPromptText("Search tools...");
L165:         searchField.setMaxWidth(Double.MAX_VALUE);
L166:         HBox.setHgrow(searchField, Priority.ALWAYS);
L167:         searchField.textProperty().addListener((obs, oldVal, newVal) -> {
L168:             currentQuery = newVal.trim().toLowerCase();
L169:             refresh();
L170:         });
L171: 
L172:         Label kbdHint = new Label("⌘K");
L173:         kbdHint.setStyle(
L174:             "-fx-font-size: 10px; -fx-text-fill: rgba(255,255,255,0.28);" +
L175:             "-fx-background-color: rgba(255,255,255,0.06);" +
L176:             "-fx-border-color: rgba(255,255,255,0.10); -fx-border-width: 1;" +
L177:             "-fx-border-radius: 4; -fx-background-radius: 4;" +
L178:             "-fx-padding: 1 5 1 5; -fx-font-family: 'SF Mono','Consolas',monospace;"
L179:         );
L180: 
L181:         HBox bar = new HBox(10, searchIcon, searchField, kbdHint);
L182:         bar.getStyleClass().add("search-bar");
L183:         bar.setAlignment(Pos.CENTER_LEFT);
L184:         bar.setPrefHeight(38);
L185:         return bar;
L186:     }
L187: 
L188:     private ScrollPane buildPageScrollPane() {
L189:         ScrollPane sp = new ScrollPane();
L190:         sp.getStyleClass().add("content-scroll");
L191:         sp.setFitToWidth(true);
L192:         sp.setFitToHeight(true);
L193:         sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
L194:         sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
L195:         sp.setStyle("-fx-background-color: transparent; -fx-background: transparent;");
L196:         return sp;
L197:     }
L198: 
L199:     private ScrollPane buildScrollPane() {
L200:         // Tool grid
L201:         toolGrid.setHgap(10);
L202:         toolGrid.setVgap(10);
L203:         toolGrid.setPadding(new Insets(16));
L204:         toolGrid.setPrefWrapLength(600);
L205: 
L206:         VBox wrapper = new VBox(
L207:             sectionHeader("FREQUENT", ""),
L208:             toolGrid
L209:         );
L210:         wrapper.setPadding(new Insets(8, 16, 16, 16));
L211:         wrapper.setSpacing(0);
L212: 
L213:         ScrollPane sp = new ScrollPane(wrapper);
L214:         sp.getStyleClass().add("content-scroll");
L215:         sp.setFitToWidth(true);
L216:         sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
L217:         sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
L218:         sp.setStyle("-fx-background-color: transparent; -fx-background: transparent;");
L219:         return sp;
L220:     }
L221: 
L222:     // ── Grid refresh ──────────────────────────────────────────
L223: 
L224:     private void refresh() {
L225:         if (plugins == null) return;
L226: 
L227:         List<SwissKitJPlugin> filtered = plugins.stream()
L228:             .filter(this::matchesCategory)
L229:             .filter(this::matchesQuery)
L230:             .toList();
L231: 
L232:         toolGrid.getChildren().clear();
L233: 
L234:         for (int i = 0; i < filtered.size(); i++) {
L235:             SwissKitJPlugin p = filtered.get(i);
L236:             ToolCard card = new ToolCard(p, this::onCardSelect);
L237:             card.setPrefWidth(152);
L238:             card.setPrefHeight(130);
L239: 
L240:             // Staggered entry delay
L241:             int delay = i * 35;
L242:             card.setOpacity(0);
L243:             PauseTransition pause = new PauseTransition(Duration.millis(delay));
L244:             pause.setOnFinished(e -> {
L245:                 FadeTransition ft = new FadeTransition(Duration.millis(240), card);
L246:                 ft.setFromValue(0); ft.setToValue(1);
L247:                 TranslateTransition tt = new TranslateTransition(Duration.millis(240), card);
L248:                 tt.setFromY(10); tt.setToY(0);
L249:                 new ParallelTransition(ft, tt).play();
L250:             });
L251:             pause.play();
L252: 
L253:             toolGrid.getChildren().add(card);
L254:         }
L255: 
L256:         // Empty state message
L257:         if (filtered.isEmpty()) {
L258:             Label empty = new Label("No matching tools found");
L259:             empty.setStyle("-fx-text-fill: rgba(255,255,255,0.28); -fx-font-size: 13px;");
L260:             empty.setPadding(new Insets(40, 0, 0, 0));
L261:             toolGrid.getChildren().add(empty);
L262:         }
L263:     }
L264: 
L265:     // ── Filter logic ──────────────────────────────────────────
L266: 
L267:     private boolean matchesCategory(SwissKitJPlugin p) {
L268:         return switch (currentCategory) {
L269:             case "all"     -> true;
L270:             case "plugins" -> !"builtin".equals(p.getType());
L271:             case "fav"     -> false; // TODO: integrate favorites persistence
L272:             default        -> p.getCategory().equalsIgnoreCase(currentCategory);
L273:         };
L274:     }
L275: 
L276:     private boolean matchesQuery(SwissKitJPlugin p) {
L277:         if (currentQuery.isEmpty()) return true;
L278:         return p.getName().toLowerCase().contains(currentQuery)
L279:             || p.getDescription().toLowerCase().contains(currentQuery);
L280:     }
L281: 
L282:     // ── Card selection ──────────────────────────────────────────
L283: 
L284:     private void onCardSelect(SwissKitJPlugin plugin) {
L285:         detailPanel.show(plugin);
L286:     }
L287: 
L288:     // ── Page transition animation (cross-fade) ──────────────────────
L289: 
L290:     private void crossFadeTo(Node next) {
L291:         Node current = pageStack.getChildren().isEmpty()
L292:             ? null : pageStack.getChildren().get(0);
L293: 
L294:         next.setOpacity(0);
L295:         if (!pageStack.getChildren().contains(next))
L296:             pageStack.getChildren().add(next);
L297:         next.toFront();
L298: 
L299:         FadeTransition fadeIn = new FadeTransition(Duration.millis(220), next);
L300:         fadeIn.setToValue(1);
L301: 
L302:         if (current != null && current != next) {
L303:             FadeTransition fadeOut = new FadeTransition(Duration.millis(180), current);
L304:             fadeOut.setToValue(0);
L305:             Node finalCurrent = current;
L306:             fadeOut.setOnFinished(e -> pageStack.getChildren().remove(finalCurrent));
L307:             new ParallelTransition(fadeOut, fadeIn).play();
L308:         } else {
L309:             fadeIn.play();
L310:         }
L311:     }
L312: 
L313:     private void animateGridIn() {
L314:         // Grid slides in from slightly below
L315:         TranslateTransition tt = new TranslateTransition(Duration.millis(280), toolGrid);
L316:         tt.setFromY(12); tt.setToY(0);
L317:         FadeTransition ft = new FadeTransition(Duration.millis(280), toolGrid);
L318:         ft.setFromValue(0.4); ft.setToValue(1);
L319:         new ParallelTransition(tt, ft).play();
L320:     }
L321: 
L322:     // ── Helper node factory ──────────────────────────────────────
L323: 
L324:     private HBox sectionHeader(String title, String action) {
L325:         Label titleLabel = new Label(title.toUpperCase());
L326:         titleLabel.getStyleClass().add("section-title");
L327: 
L328:         Region spacer = new Region();
L329:         HBox.setHgrow(spacer, Priority.ALWAYS);
L330: 
L331:         HBox row = new HBox(titleLabel, spacer);
L332:         if (!action.isEmpty()) {
L333:             Label actionLabel = new Label(action);
L334:             actionLabel.setStyle("-fx-text-fill: #5b8cf7; -fx-font-size: 12px; -fx-cursor: hand;");
L335:             row.getChildren().add(actionLabel);
L336:         }
