L1: package fan.summer.plugin;
L2: 
L3: import fan.summer.api.SwissKitJPlugin;
L4: import javafx.application.Platform;
L5: import org.slf4j.Logger;
L6: import org.slf4j.LoggerFactory;
L7: 
L8: import java.io.IOException;
L9: import java.net.URLClassLoader;
L10: import java.nio.file.*;
L11: import java.util.*;
L12: import java.util.concurrent.atomic.AtomicBoolean;
L13: 
L14: /**
L15:  * Scans a plugins/ directory for JAR files, loads SwissKitJPlugin implementations
L16:  * via ServiceLoader, and watches for hot-reload on file changes.
L17:  */
L18: public class PluginLoader {
L19: 
L20:     private static final Logger log = LoggerFactory.getLogger(PluginLoader.class);
L21: 
L22:     private final Path        pluginsDir;
L23:     private PluginRegistry registry;
L24:     private WatchService      watchService;
L25:     private Thread            watchThread;
L26:     private final AtomicBoolean running = new AtomicBoolean(false);
L27: 
L28:     /** Maps JAR path → the ClassLoader opened for it (for unloading) */
L29:     private final Map<Path, URLClassLoader> openLoaders = new LinkedHashMap<>();
L30: 
L31:     /** Maps JAR path → plugins loaded from that JAR */
L32:     private final Map<Path, List<SwissKitJPlugin>> jarPlugins = new LinkedHashMap<>();
L33: 
L34:     public PluginLoader(Path pluginsDir) {
L35:         this.pluginsDir = pluginsDir;
L36:     }
L37: 
L38:     // Called by PluginRegistry after construction
L39:     void setRegistry(PluginRegistry registry) {
L40:         this.registry = registry;
L41:     }
L42: 
L43:     // ── Lifecycle ────────────────────────────────────────────────
L44: 
L45:     public void start() {
L46:         if (!running.compareAndSet(false, true)) {
L47:             log.debug("PluginLoader already running, ignoring duplicate start()");
L48:             return;
L49:         }
L50:         log.info("Starting plugin loader, directory={}", pluginsDir.toAbsolutePath());
L51: 
L52:         // Initial scan
L53:         scanAll();
L54: 
L55:         // Watch for JAR add/remove
L56:         try {
L57:             if (Files.isDirectory(pluginsDir)) {
L58:                 watchService = FileSystems.getDefault().newWatchService();
L59:                 pluginsDir.register(watchService,
L60:                     StandardWatchEventKinds.ENTRY_CREATE,
L61:                     StandardWatchEventKinds.ENTRY_DELETE,
L62:                     StandardWatchEventKinds.ENTRY_MODIFY
L63:                 );
L64:                 watchThread = new Thread(this::watchLoop, "plugin-watcher");
L65:                 watchThread.setDaemon(true);
L66:                 watchThread.start();
L67:                 log.info("Plugin directory watcher active");
L68:             } else {
L69:                 log.warn("Plugin directory does not exist, hot-reload disabled: {}", pluginsDir);
L70:             }
L71:         } catch (IOException e) {
L72:             log.warn("Cannot start plugin watcher: {}", e.getMessage(), e);
L73:         }
L74:     }
L75: 
L76:     public void stop() {
L77:         log.info("Stopping plugin loader");
L78:         running.set(false);
L79:         try {
L80:             if (watchService != null) watchService.close();
L81:         } catch (IOException ignored) {}
L82:         if (watchThread != null) watchThread.interrupt();
L83: 
L84:         // Unload all plugins
L85:         List<Path> jars = new ArrayList<>(jarPlugins.keySet());
L86:         log.debug("Unloading {} JAR(s) on shutdown", jars.size());
L87:         jars.forEach(this::unloadJar);
L88:     }
L89: 
L90:     // ── Scan ────────────────────────────────────────────────────
L91: 
L92:     private void scanAll() {
L93:         if (!Files.isDirectory(pluginsDir)) {
L94:             log.debug("Skipping plugin scan, directory does not exist: {}", pluginsDir);
L95:             return;
L96:         }
L97:         int found = 0;
L98:         try (DirectoryStream<Path> stream = Files.newDirectoryStream(pluginsDir, "*.jar")) {
L99:             for (Path jar : stream) {
L100:                 if (!jarPlugins.containsKey(jar)) {
L101:                     loadJar(jar);
L102:                     found++;
L103:                 }
L104:             }
L105:         } catch (IOException e) {
L106:             log.warn("Plugin scan failed: {}", e.getMessage(), e);
L107:         }
L108:         log.info("Initial plugin scan complete, processed {} JAR(s)", found);
L109:     }
L110: 
L111:     // ── JAR load / unload ────────────────────────────────────────
L112: 
L113:     private void loadJar(Path jar) {
L114:         log.debug("Loading plugin JAR: {}", jar.getFileName());
L115:         try {
L116:             URLClassLoader cl = new URLClassLoader(
L117:                 new java.net.URL[]{jar.toUri().toURL()},
L118:                 getClass().getClassLoader()
L119:             );
L120:             ServiceLoader<SwissKitJPlugin> sl = ServiceLoader.load(SwissKitJPlugin.class, cl);
L121: 
L122:             List<SwissKitJPlugin> loaded = new ArrayList<>();
L123:             for (SwissKitJPlugin plugin : sl) {
L124:                 loaded.add(plugin);
L125:                 log.info("Loaded plugin: id={}, name={}, version={}, jar={}",
L126:                         plugin.getId(), plugin.getName(), plugin.getVersion(), jar.getFileName());
L127:             }
L128: 
L129:             if (loaded.isEmpty()) {
L130:                 log.warn("No SwissKitJPlugin services declared in {}", jar.getFileName());
L131:                 cl.close();
L132:                 return;
L133:             }
L134: 
L135:             openLoaders.put(jar, cl);
L136:             jarPlugins.put(jar, loaded);
L137: 
L138:             if (registry != null) {
L139:                 Platform.runLater(() -> registry.addPlugins(loaded));
L140:             }
L141:         } catch (Exception e) {
L142:             log.warn("Failed to load JAR {}: {}", jar.getFileName(), e.getMessage(), e);
L143:         }
L144:     }
L145: 
L146:     private void unloadJar(Path jar) {
L147:         List<SwissKitJPlugin> plugins = jarPlugins.remove(jar);
L148:         if (plugins != null) {
L149:             log.info("Unloading plugin JAR: {} (contained {} plugin(s))", jar.getFileName(), plugins.size());
L150:             if (registry != null) {
L151:                 Platform.runLater(() -> plugins.forEach(registry::removePlugin));
L152:             }
L153:         }
L154: 
L155:         URLClassLoader cl = openLoaders.remove(jar);
L156:         if (cl != null) {
L157:             try {
L158:                 cl.close();
L159:             } catch (IOException e) {
L160:                 log.warn("Error closing ClassLoader for {}: {}", jar.getFileName(), e.getMessage());
L161:             }
L162:         }
L163:     }
L164: 
L165:     // ── Watch loop ───────────────────────────────────────────────
L166: 
L167:     private void watchLoop() {
L168:         while (running.get()) {
L169:             try {
L170:                 WatchKey key = watchService.take();
L171:                 for (WatchEvent<?> event : key.pollEvents()) {
L172:                     Path name    = (Path) event.context();
L173:                     Path fullPath = pluginsDir.resolve(name);
L174: 
L175:                     if (!name.toString().endsWith(".jar")) continue;
L176: 
L177:                     WatchEvent.Kind<?> kind = event.kind();
L178:                     if (kind == StandardWatchEventKinds.ENTRY_CREATE) {
L179:                         log.info("Detected new plugin JAR: {}", name);
L180:                         // Brief delay so the file is fully written before reading
L181:                         Thread.sleep(500);
L182:                         loadJar(fullPath);
L183:                     } else if (kind == StandardWatchEventKinds.ENTRY_DELETE) {
L184:                         log.info("Detected plugin JAR removal: {}", name);
L185:                         unloadJar(fullPath);
L186:                     } else if (kind == StandardWatchEventKinds.ENTRY_MODIFY) {
L187:                         log.info("Detected plugin JAR modification, reloading: {}", name);
L188:                         unloadJar(fullPath);
L189:                         Thread.sleep(500);
L190:                         loadJar(fullPath);
L191:                     }
L192:                 }
L193:                 key.reset();
L194:             } catch (InterruptedException e) {
L195:                 Thread.currentThread().interrupt();
L196:                 break;
L197:             } catch (ClosedWatchServiceException e) {
L198:                 break;
L199:             }
L200:         }
L201:     }
L202: }
