L17: public class DatabaseInit {
L18: 
L19:     private static final Logger logger = LoggerFactory.getLogger(DatabaseInit.class);
L20: 
L21:     private static final String DB_URL;
L22: 
L23:     static {
L24:         String dbPath = Path.of(System.getProperty("user.dir"))
L25:                 .resolve(".swisskit")
L26:                 .resolve("swisskit")
L27:                 .toAbsolutePath()
L28:                 .toString()
L29:                 .replace("\\", "/");
L30:         DB_URL = "jdbc:h2:file:" + dbPath
L31:                 + ";AUTO_SERVER=TRUE"
L32:                 + ";INIT=CREATE SCHEMA IF NOT EXISTS PUBLIC\\;SET SCHEMA PUBLIC";
L33:     }
L34: 
L35:     private static SqlSessionFactory sqlSessionFactory;
L36: 
L37:     /**
L38:      * Initializes the database connection and creates necessary tables.
L39:      * This method should be called once at application startup.
L40:      */
L41:     public static void init() {
L42:         try {
L43:             // Ensure database directory exists
L44:             Path dbDir = Path.of(System.getProperty("user.dir")).resolve(".swisskit");
L45:             if (!Files.exists(dbDir)) {
L46:                 Files.createDirectories(dbDir);
L47:                 logger.info("Created database directory: {}", dbDir.toAbsolutePath());
L48:             }
L49: 
L50:             createTables();
L51:             initMyBatis();
L52: 
L53:             logger.info("Database initialization completed, url={}", DB_URL);
L54:         } catch (Exception e) {
L55:             logger.error("Failed to initialize database", e);
L56:             throw new RuntimeException("Database initialization failed", e);
L57:         }
L58:     }
L59: 
L60:     /**
L61:      * Creates database tables by executing init.sql script.
L62:      * The script is loaded from classpath resources.
L63:      */
L64:     private static void createTables() {
L65:         try {
L66:             Class.forName("org.h2.Driver");
L67:         } catch (ClassNotFoundException e) {
L68:             throw new RuntimeException("H2 driver not found", e);
L69:         }
L70: 
L71:         // Read init.sql from classpath as stream (works inside JAR)
L72:         try (InputStream initSqlStream = DatabaseInit.class.getClassLoader()
L73:                 .getResourceAsStream("init.sql")) {
L74: 
L75:             if (initSqlStream == null) {
L76:                 throw new RuntimeException("Cannot find init.sql in classpath");
L77:             }
L78: 
L79:             // Read the SQL content
L80:             String initSqlContent = new String(initSqlStream.readAllBytes());
L81: 
L82:             try (Connection conn = DriverManager.getConnection(DB_URL);
L83:                  Statement stmt = conn.createStatement()) {
L84: 
L85:                 // Execute SQL statements directly
L86:                 stmt.execute(initSqlContent);
L87:                 logger.info("Database tables verified/created successfully from init.sql");
L88: 
L89:             }
L90:         } catch (Exception e) {
L91:             logger.error("Failed to create database tables", e);
L92:             throw new RuntimeException("Failed to create database tables", e);
L93:         }
L94:     }
L95: 
L96:     /**
L97:      * Initializes MyBatis SqlSessionFactory with database configuration.
L98:      * Loads mybatis-config.xml from classpath and injects dynamic database URL.
L99:      */
L100:     private static void initMyBatis() {
L101:         try (InputStream configStream = DatabaseInit.class.getClassLoader()
L102:                 .getResourceAsStream("mybatis-config.xml")) {
L103: 
L104:             if (configStream == null) {
L105:                 throw new RuntimeException("Cannot find mybatis-config.xml");
L106:             }
L107: 
L108:             // Inject dynamic URL into mybatis-config.xml ${db.url} placeholder via Properties
L109:             Properties props = new Properties();
L110:             props.setProperty("db.url", DB_URL);
L111: 
L112:             sqlSessionFactory = new SqlSessionFactoryBuilder()
L113:                     .build(configStream, props);
L114: 
L115:             logger.info("MyBatis SqlSessionFactory initialized");
L116: 
L117:         } catch (Exception e) {
L118:             logger.error("Failed to initialize MyBatis", e);
L119:             throw new RuntimeException("Failed to initialize MyBatis", e);
L120:         }
L121:     }
L122: 
L123:     /**
L124:      * Returns a new SqlSession for database operations.
L125:      * Caller is responsible for closing the session after use.
L126:      *
L127:      * @return a new SqlSession instance
L128:      * @throws IllegalStateException if database is not initialized
L129:      */
L130:     public static SqlSession getSqlSession() {
L131:         if (sqlSessionFactory == null) {
L132:             throw new IllegalStateException("Database not initialized. Call init() first.");
L133:         }
L134:         return sqlSessionFactory.openSession();
L135:     }
L136: 
L137:     /**
L138:      * Returns the SqlSessionFactory instance for advanced MyBatis usage.
L139:      *
L140:      * @return the SqlSessionFactory instance
L141:      * @throws IllegalStateException if database is not initialized
L142:      */
L143:     public static SqlSessionFactory getSqlSessionFactory() {
L144:         if (sqlSessionFactory == null) {
L145:             throw new IllegalStateException("Database not initialized. Call init() first.");
L146:         }
L147:         return sqlSessionFactory;
L148:     }
L149: 
L150:     /**
L151:      * Checks if the database has been initialized.
L152:      *
L153:      * @return true if database is initialized, false otherwise
L154:      */
L155:     public static boolean isInitialized() {
L156:         return sqlSessionFactory != null;
L157:     }
L158: }
