L76:             .replaceAll("\\*\\*(.+?)\\*\\*", "<strong>$1</strong>")
L77:             .replaceAll("\\*(.+?)\\*",        "<em>$1</em>")
L78:             .replaceAll("`(.+?)`",            "<code>$1</code>")
