L179:     private void handleSend(TextField subjectField, TextField toField, TextField ccField,
L180:                             RichTextEditor bodyEditor, boolean massMode,
L181:                             ProgressBar progressBar, Label progressLabel, Button sendBtn) {
L182:         String subject = subjectField.getText();
L183:         String body = bodyEditor.getHtml();
L184:         String plain = bodyEditor.getPlainText();
L185:         if (subject == null || subject.isBlank()) {
L186:             alert(Alert.AlertType.WARNING, "提示", "请填写主题");
L187:             return;
L188:         }
L189:         if (plain == null || plain.isBlank()) {
L190:             alert(Alert.AlertType.WARNING, "提示", "请填写正文");
L191:             return;
L192:         }
L193: 
L194:         sendBtn.setDisable(true);
L195:         progressBar.setProgress(0);
L196:         progressBar.getStyleClass().removeAll("success", "danger");
L197:         progressLabel.setText("准备发送...");
L198:         progressLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.55); -fx-font-size: 12px;");
L199: 
L200:         Task<EmailSendService.Result> task = new Task<>() {
L201:             @Override
L202:             protected EmailSendService.Result call() {
L203:                 EmailSendService service = new EmailSendService();
L204:                 if (massMode) {
L205:                     if (massTaskId == null) {
L206:                         EmailSendService.Result r = new EmailSendService.Result();
L207:                         r.errorMessage = "未配置群发任务";
L208:                         return r;
L209:                     }
L210:                     return service.sendMass(subject, body, massTaskId,
L211:                             (pct, msg) -> Platform.runLater(() -> {
L212:                                 progressBar.setProgress(pct);
L213:                                 progressLabel.setText(msg);
L214:                             }));
L215:                 } else {
L216:                     List<String> toList = splitAddresses(toField.getText());
L217:                     if (toList.isEmpty()) {
L218:                         EmailSendService.Result r = new EmailSendService.Result();
L219:                         r.errorMessage = "请填写收件人";
L220:                         return r;
L221:                     }
L222:                     List<String> ccList = splitAddresses(ccField.getText());
L223:                     Platform.runLater(() -> {
L224:                         progressBar.setProgress(-1);
L225:                         progressLabel.setText("发送中...");
L226:                     });
L227:                     return service.sendSingle(subject, body, toList, ccList, null, null);
L228:                 }
L229:             }
L230:         };
L231: 
L232:         task.setOnSucceeded(e -> {
L233:             sendBtn.setDisable(false);
L234:             EmailSendService.Result r = task.getValue();
L235:             progressBar.setProgress(1.0);
L236:             progressBar.getStyleClass().removeAll("success", "danger");
L237:             if (r.errorMessage != null) {
L238:                 progressBar.getStyleClass().add("danger");
L239:                 progressLabel.setText("❌ " + r.errorMessage);
L240:                 progressLabel.setStyle("-fx-text-fill: #f25c5c; -fx-font-size: 12px;");
L241:             } else {
L242:                 progressBar.getStyleClass().add("success");
L243:                 progressLabel.setText("✓ 完成：成功 " + r.successCount + "，失败 " + r.failCount);
L244:                 progressLabel.setStyle("-fx-text-fill: #4cd97b; -fx-font-size: 12px;");
L245:             }
L246:         });
L247:         task.setOnFailed(e -> {
L248:             sendBtn.setDisable(false);
L249:             progressBar.setProgress(0);
L250:             progressBar.getStyleClass().removeAll("success", "danger");
L251:             progressBar.getStyleClass().add("danger");
L252:             Throwable ex = task.getException();
L253:             progressLabel.setText("❌ 发送任务异常：" + (ex != null ? ex.getMessage() : "unknown"));
L254:             progressLabel.setStyle("-fx-text-fill: #f25c5c; -fx-font-size: 12px;");
L255:             log.error("Send task failed", ex);
L256:         });
L257: 
L258:         new Thread(task) {{ setDaemon(true); }}.start();
L259:     }
