L169:         java.util.function.BooleanSupplier canProceedSupplier() {
L170:             return () -> {
L171:                 if (config.analysisResult != null) return true;
L172:                 if (config.sourceFile == null) return false;
L173:                 // Analysis hasn't started yet — trigger it now (first Next click with file selected)
L174:                 if (!analysisRunning.get() && !analysisTriggered) {
L175:                     analysisTriggered = true;
L176:                     analysisRunning.set(true);
L177:                     Platform.runLater(() -> showLoading(true));
L178:                     startAnalysis();
L179:                 }
L180:                 // While running, return false silently (no shake — wizard sees false and stays)
L181:                 return false;
L182:             };
L183:         }
