L185:         private void startAnalysis() {
L186:             Task<Map<String, Map<Integer, String>>> task = new Task<>() {
L187:                 @Override
L188:                 protected Map<String, Map<Integer, String>> call() throws Exception {
L189:                     return ExcelSplitter.analyze(config.sourceFile);
L190:                 }
L191:             };
L192: 
L193:             task.setOnSucceeded(e -> {
L194:                 config.analysisResult = task.getValue();
L195:                 analysisRunning.set(false);
L196:                 showLoading(false);
L197:                 int sheetCount = config.analysisResult.size();
L198:                 statusLabel.setText("✓ 共 " + sheetCount + " 个Sheet：" +
L199:                     config.analysisResult.keySet().stream().limit(5).collect(Collectors.joining(", ")) +
L200:                     (sheetCount > 5 ? " …" : ""));
L201:                 statusLabel.setStyle("-fx-text-fill: #4cd97b; -fx-font-size: 12px;");
L202:                 // Automatically advance to step 2 now that analysis is done
L203:                 wizard.goTo(1);
L204:             });
L205: 
L206:             task.setOnFailed(e -> {
L207:                 analysisRunning.set(false);
L208:                 analysisTriggered = false;
L209:                 showLoading(false);
L210:                 statusLabel.setText("❌ 分析失败：" + task.getException().getMessage());
L211:                 statusLabel.setStyle("-fx-text-fill: #f25c5c; -fx-font-size: 12px;");
L212:             });
L213: 
L214:             new Thread(task) {{ setDaemon(true); }}.start();
L215:         }
