L27: /**
L28:  * Root node of the main window.
L29:  * Assembles TitleBar / Sidebar / ContentArea / StatusBar,
L30:  * and holds the lifecycle for PluginLoader and PluginRegistry.
L31:  */
L32: public class MainWindow extends StackPane {
L33: 
L34:     private static final Logger log = LoggerFactory.getLogger(MainWindow.class);
L35: 
L36:     private final Stage        stage;
L37:     private final PluginLoader loader;
L38:     private final PluginRegistry registry;
L39: 
L40:     private final TitleBar    titleBar;
L41:     private final Sidebar     sidebar;
L42:     private final ContentArea contentArea;
L43: 
L44:     // Status bar labels
L45:     private Label statusToolCount    = statusText("0 tools");
L46:     private Label statusPluginCount  = statusText("0 plugins");
L47:     private final Label clockLabel         = statusText("");
L48: 
L49:     private Timeline clockTimeline;
