L51:     public MainWindow(Stage stage, PluginLoader loader, PluginRegistry registry) {
L52:         log.debug("Initialising MainWindow");
L53:         this.stage    = stage;
L54:         this.loader   = loader;
L55:         this.registry = registry;
L56: 
L57:         titleBar    = new TitleBar(stage, this::openSettings);
L58:         sidebar     = new Sidebar();
L59:         contentArea = new ContentArea();
L60: 
L61:         int buildInTool = 0;
L62:         int pluginInTool = 0;
L63:         for (SwissKitJPlugin plugin : registry.getPlugins()) {
L64:             if(plugin.getType().equals("plugin") ) {
L65:                 pluginInTool++;
L66:             }else {
L67:                 buildInTool++;
L68:             }
L69:         }
L70: 
L71:         statusPluginCount = statusText(pluginInTool + "plugins");
L72:         statusToolCount = statusText(pluginInTool + buildInTool +  "tools");
L73: 
L74:         buildScene();
L75:         wireEvents();
L76:         startClock();
L77:         playEntryAnimation();
L78:     }
L79: 
L80:     // ── Build scene graph ────────────────────────────────
L81: 
L82:     private void buildScene() {
L83:         // Background orb layer (bottom layer)
L84:         Pane orbLayer = buildOrbLayer();
L85: 
L86:         // Main window glass panel
L87:         BorderPane windowPane = new BorderPane();
L88:         windowPane.getStyleClass().add("app-root");
L89:         windowPane.setStyle(
L90:             "-fx-background-color: rgba(13,14,17,0.72);" +
L91:             "-fx-background-radius: 20;" +
L92:             "-fx-border-radius: 20;" +
L93:             "-fx-border-color: rgba(255,255,255,0.10);" +
L94:             "-fx-border-width: 1;" +
L95:             "-fx-effect: dropshadow(gaussian, rgba(0,0,0,0.6), 60, 0, 0, 20);"
L96:         );
L97: 
L98:         // Title bar
L99:         windowPane.setTop(titleBar);
L100: 
L101:         // Body: sidebar + content area
L102:         HBox body = new HBox(sidebar, contentArea);
L103:         HBox.setHgrow(contentArea, Priority.ALWAYS);
L104:         windowPane.setCenter(body);
L105: 
L106:         // Status bar
L107:         windowPane.setBottom(buildStatusBar());
L108: 
L109:         // Top highlight border (glass thickness simulation)
L110:         Rectangle topHighlight = new Rectangle();
L111:         topHighlight.setMouseTransparent(true);
L112:         topHighlight.setStyle(
L113:             "-fx-fill: transparent;" +
L114:             "-fx-stroke: rgba(255,255,255,0.12);" +
L115:             "-fx-stroke-width: 1;" +
L116:             "-fx-arc-width: 40; -fx-arc-height: 40;"
L117:         );
L118:         topHighlight.widthProperty().bind(widthProperty());
L119:         topHighlight.heightProperty().bind(heightProperty());
L120: 
L121:         getChildren().addAll(orbLayer, windowPane, topHighlight);
L122:         setAlignment(windowPane, Pos.CENTER);
L123:         setAlignment(topHighlight, Pos.CENTER);
L124:     }
L125: 
L126:     // ── Background orbs ───────────────────────────────────
L127: 
L128:     private Pane buildOrbLayer() {
L129:         Pane layer = new Pane();
L130:         layer.setMouseTransparent(true);
L131:         layer.setStyle("-fx-background-color: #0d0e11;");
L132: 
L133:         // Three colored Gaussian blur orbs
L134:         layer.getChildren().addAll(
L135:             orb(480, "#3b5bdb", -80, -120, 0),
L136:             orb(360, "#7048e8",  -60, 200,  -6000),
L137:             orb(300, "#1c7ed6",  300, 400, -12000)
L138:         );
L139:         return layer;
L140:     }
L141: 
L142:     private StackPane orb(double size, String color, double x, double y, double animDelay) {
L143:         Circle c = new Circle(size / 2,
L144:             Color.web(color, 0.28));
L145:         c.setEffect(new javafx.scene.effect.GaussianBlur(60));
L146: 
L147:         StackPane wrap = new StackPane(c);
L148:         wrap.setTranslateX(x);
L149:         wrap.setTranslateY(y);
L150:         wrap.setMouseTransparent(true);
L151: 
L152:         // Floating animation
L153:         TranslateTransition drift = new TranslateTransition(Duration.millis(18000), wrap);
L154:         drift.setByX(30); drift.setByY(20);
L155:         drift.setAutoReverse(true);
L156:         drift.setCycleCount(Animation.INDEFINITE);
L157:         drift.setDelay(Duration.millis(Math.abs(animDelay)));
L158:         drift.setInterpolator(Interpolator.EASE_BOTH);
L159:         drift.play();
L160: 
L161:         ScaleTransition breathe = new ScaleTransition(Duration.millis(12000), wrap);
L162:         breathe.setFromX(1.0); breathe.setFromY(1.0);
L163:         breathe.setToX(1.08);  breathe.setToY(1.08);
L164:         breathe.setAutoReverse(true);
L165:         breathe.setCycleCount(Animation.INDEFINITE);
L166:         breathe.setInterpolator(Interpolator.EASE_BOTH);
L167:         breathe.play();
L168: 
L169:         return wrap;
L170:     }
L171: 
L172:     // ── Status bar ───────────────────────────────────────
L173: 
L174:     private HBox buildStatusBar() {
L175:         // Activity indicator dot
L176:         Circle dot = new Circle(3, Color.web("#4cd97b"));
L177:         dot.setEffect(new javafx.scene.effect.Glow(0.8));
L178:         FadeTransition pulse = new FadeTransition(Duration.millis(2500), dot);
L179:         pulse.setFromValue(1.0); pulse.setToValue(0.4);
L180:         pulse.setAutoReverse(true); pulse.setCycleCount(Animation.INDEFINITE);
L181:         pulse.play();
L182: 
L183:         Label sep = statusText("·");
L184:         sep.setStyle("-fx-text-fill: rgba(255,255,255,0.15); -fx-font-size: 11px;");
L185: 
L186:         Region spacer = new Region();
L187:         HBox.setHgrow(spacer, Priority.ALWAYS);
L188: 
L189:         HBox bar = new HBox(10);
L190:         bar.getStyleClass().add("statusbar");
L191:         bar.setAlignment(Pos.CENTER_LEFT);
L192:         bar.setPadding(new Insets(0, 16, 0, 16));
L193:         bar.getChildren().addAll(dot, statusToolCount, sep, statusPluginCount, spacer, clockLabel);
L194:         return bar;
L195:     }
L196: 
L197:     private Label statusText(String text) {
L198:         Label l = new Label(text);
L199:         l.getStyleClass().add("status-text");
L200:         return l;
L201:     }
L202: 
L203:     // ── Event wiring ─────────────────────────────────────
L204: 
L205:     private void wireEvents() {
L206:         // Bind plugin list to content area
L207:         contentArea.setPlugins(registry.getPlugins());
L208: 
L209:         // Sidebar category switch → content area filter
L210:         sidebar.setOnCategorySelect(categoryId -> {
L211:             if ("store".equals(categoryId)) {
L212:                 contentArea.showPage(fan.summer.ui.store.PluginStoreUi.build(), "Plugin Store");
L213:             } else if ("settings".equals(categoryId)) {
L214:                 // settings is handled by setOnSettingsSelect
L215:             } else {
L216:                 contentArea.showCategory(categoryId);
L217:             }
L218:         });
L219: 
L220:         // Settings (standalone, not part of nav state machine)
L221:         sidebar.setOnSettingsSelect(this::openSettings);
L222: 
L223:         // Plugin list change → update status bar
L224:         registry.getPlugins().addListener(
L225:             (javafx.collections.ListChangeListener<SwissKitJPlugin>) c -> {
L226:                 int total   = registry.getPlugins().size();
L227:                 int plugins = (int) registry.getPlugins().stream()
L228:                     .filter(p -> !"builtin".equals(p.getType())).count();
L229:                 statusToolCount.setText(total + " tools");
L230:                 statusPluginCount.setText(plugins + " plugins");
L231:                 sidebar.updateBadge("plugins", plugins);
L232:             }
L233:         );
L234: 
L235:         // Tool launch callback
L236:         contentArea.setOnLaunch(plugin -> {
L237:             log.info("Launching tool: id={}, name={}", plugin.getId(), plugin.getName());
L238:             registry.activate(plugin);
L239:             try {
L240:                 contentArea.showPage(plugin.createView(), plugin.getName());
L241:             } catch (Exception e) {
L242:                 log.error("Failed to create view for plugin {}: {}", plugin.getId(), e.getMessage(), e);
L243:             }
L244:         });
L245: 
L246:         // Back / exit plugin view callback
L247:         contentArea.setOnBack(() -> {
L248:             log.debug("Returning to home from active plugin");
L249:             registry.deactivate();
L250:         });
L251:     }
L252: 
L253:     // ── Settings page ────────────────────────────────────
L254: 
L255:     private void openSettings() {
L256:         Node settingsPage = SwissKitJSettingUi.build();
L257:         contentArea.showPage(settingsPage, "Settings");
L258:     }
L259: 
L260:     // ── Entry animation ──────────────────────────────────
L261: 
L262:     private void playEntryAnimation() {
L263:         // Get windowPane (second child node)
L264:         javafx.scene.Node windowPane = getChildren().get(1);
L265:         windowPane.setOpacity(0);
L266:         windowPane.setScaleX(0.94);
L267:         windowPane.setScaleY(0.94);
L268:         windowPane.setTranslateY(16);
L269: 
L270:         FadeTransition ft = new FadeTransition(Duration.millis(500), windowPane);
L271:         ft.setToValue(1);
L272: 
L273:         ScaleTransition st = new ScaleTransition(Duration.millis(500), windowPane);
L274:         st.setToX(1); st.setToY(1);
L275:         st.setInterpolator(Interpolator.SPLINE(0.34, 0.9, 0.64, 1.0));
L276: 
L277:         TranslateTransition tt = new TranslateTransition(Duration.millis(500), windowPane);
L278:         tt.setToY(0);
L279:         tt.setInterpolator(Interpolator.SPLINE(0.34, 0.9, 0.64, 1.0));
L280: 
L281:         new ParallelTransition(ft, st, tt).play();
L282:     }
L283: 
L284:     // ── Clock ────────────────────────────────────────────
L285: 
L286:     private void startClock() {
L287:         DateTimeFormatter fmt = DateTimeFormatter.ofPattern("HH:mm:ss");
L288:         clockTimeline = new Timeline(new KeyFrame(Duration.seconds(1), e ->
L289:             clockLabel.setText(LocalTime.now().format(fmt))
L290:         ));
L291:         clockTimeline.setCycleCount(Animation.INDEFINITE);
L292:         clockTimeline.play();
L293:         clockLabel.setText(LocalTime.now().format(fmt)); // Initial display
L294:     }
L295: 
L296:     /** Called on application exit to clean up resources */
L297:     public void shutdown() {
L298:         log.debug("MainWindow shutting down resources");
L299:         if (clockTimeline != null) clockTimeline.stop();
L300:         loader.stop();
L301:     }
L302: }
