L140:         conn.setReadTimeout(15000);
L141:         conn.setRequestProperty("Accept", "application/json");
L142: 
L143:         int responseCode = conn.getResponseCode();
L144:         if (responseCode != 200) {
L145:             throw new RuntimeException("HTTP " + responseCode);
L146:         }
L147: 
L148:         StringBuilder sb = new StringBuilder();
L149:         try (BufferedReader br = new BufferedReader(new InputStreamReader(conn.getInputStream()))) {
L150:             String line;
